import{_ as e,c as t,o,a1 as l}from"./chunks/framework.DDNAyvCW.js";const r="/assets/autocomplete.D_6AQM9H.png",m=JSON.parse('{"title":"命令补全","description":"","frontmatter":{},"headers":[],"relativePath":"docs/terminal/autocomplete/index.md","filePath":"docs/terminal/autocomplete/index.md"}'),i={name:"docs/terminal/autocomplete/index.md"};function n(s,a,d,c,h,u){return o(),t("div",null,a[0]||(a[0]=[l('<h1 id="命令补全" tabindex="-1">命令补全 <a class="header-anchor" href="#命令补全" aria-label="Permalink to &quot;命令补全&quot;">​</a></h1><p>Chaterm 提供命令补全功能，在终端输入时会自动给出建议，帮助您更快输入常用命令。</p><p><img src="'+r+'" alt=""></p><h2 id="功能概览" tabindex="-1">功能概览 <a class="header-anchor" href="#功能概览" aria-label="Permalink to &quot;功能概览&quot;">​</a></h2><p>命令补全会综合以下来源：</p><ul><li><strong>历史命令</strong>：支持跨主机命令推荐，优先推荐当前服务器的历史命令，同时补充其他服务器的常用命令。</li><li><strong>内置命令库</strong>：补充常见 Linux/Shell 命令。</li><li><strong>AI 智能建议（可选）</strong>：基于当前输入生成更完整的命令建议。</li></ul><p>其中，跨主机推荐会优先匹配当前服务器的使用习惯，再补充您在其他服务器上常用的相关命令。</p><h2 id="使用方式" tabindex="-1">使用方式 <a class="header-anchor" href="#使用方式" aria-label="Permalink to &quot;使用方式&quot;">​</a></h2><ol><li>在终端开始输入命令，补全面板会自动出现。</li><li>按 <code>→</code> 进入选择模式。</li><li>按 <code>↑</code> / <code>↓</code> 切换建议。</li><li>按 <code>Enter</code> 确认填入命令。</li><li>按 <code>Esc</code> 或 <code>←</code> 退出选择/关闭面板。</li></ol><h2 id="配置项" tabindex="-1">配置项 <a class="header-anchor" href="#配置项" aria-label="Permalink to &quot;配置项&quot;">​</a></h2><p>在 <strong>设置 &gt; 扩展设置</strong> 中可开启或关闭 <strong>自动补全</strong>：</p><ul><li><strong>开启</strong>：输入时显示补全建议（推荐）。</li><li><strong>关闭</strong>：不显示补全面板，按传统方式手动输入。</li></ul><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><h3 id="没有看到补全面板" tabindex="-1">没有看到补全面板？ <a class="header-anchor" href="#没有看到补全面板" aria-label="Permalink to &quot;没有看到补全面板？&quot;">​</a></h3><ul><li>确认已在 <strong>设置 &gt; 扩展设置</strong> 中开启 <strong>自动补全</strong>。</li><li>先输入一段命令前缀，再等待建议刷新。</li></ul><h3 id="ai-建议没有出现" tabindex="-1">AI 建议没有出现？ <a class="header-anchor" href="#ai-建议没有出现" aria-label="Permalink to &quot;AI 建议没有出现？&quot;">​</a></h3><ul><li>网络异常时 AI 建议可能暂不可用，但本地补全不受影响。</li></ul>',17)]))}const _=e(i,[["render",n]]);export{m as __pageData,_ as default};
